import java.io.*;
import junit.framework.TestCase;

/** Agent tests for Assignment 4: ref cells, blocks, and mutation. */
public class Assign4AgentTest extends TestCase {

  public Assign4AgentTest(String name) { super(name); }

  private void valueValueCheck(String name, String answer, String program) {
    Interpreter interp = new Interpreter(new StringReader(program));
    assertEquals("by-value-value " + name, answer, interp.valueValue().toString());
  }

  private void nameNameCheck(String name, String answer, String program) {
    Interpreter interp = new Interpreter(new StringReader(program));
    assertEquals("by-name-name " + name, answer, interp.nameName().toString());
  }

  private void needNeedCheck(String name, String answer, String program) {
    Interpreter interp = new Interpreter(new StringReader(program));
    assertEquals("by-need-need " + name, answer, interp.needNeed().toString());
  }

  private void allCheck(String name, String answer, String program) {
    Interpreter interp;
    interp = new Interpreter(new StringReader(program));
    assertEquals("vv " + name, answer, interp.valueValue().toString());
    interp = new Interpreter(new StringReader(program));
    assertEquals("vn " + name, answer, interp.valueName().toString());
    interp = new Interpreter(new StringReader(program));
    assertEquals("vd " + name, answer, interp.valueNeed().toString());
    interp = new Interpreter(new StringReader(program));
    assertEquals("nv " + name, answer, interp.nameValue().toString());
    interp = new Interpreter(new StringReader(program));
    assertEquals("nn " + name, answer, interp.nameName().toString());
    interp = new Interpreter(new StringReader(program));
    assertEquals("nd " + name, answer, interp.nameNeed().toString());
    interp = new Interpreter(new StringReader(program));
    assertEquals("dv " + name, answer, interp.needValue().toString());
    interp = new Interpreter(new StringReader(program));
    assertEquals("dn " + name, answer, interp.needName().toString());
    interp = new Interpreter(new StringReader(program));
    assertEquals("dd " + name, answer, interp.needNeed().toString());
  }

  private void noNameCheck(String name, String answer, String program) {
    Interpreter interp;
    interp = new Interpreter(new StringReader(program));
    assertEquals("vv " + name, answer, interp.valueValue().toString());
    interp = new Interpreter(new StringReader(program));
    assertEquals("vn " + name, answer, interp.valueName().toString());
    interp = new Interpreter(new StringReader(program));
    assertEquals("vd " + name, answer, interp.valueNeed().toString());
    interp = new Interpreter(new StringReader(program));
    assertEquals("dv " + name, answer, interp.needValue().toString());
    interp = new Interpreter(new StringReader(program));
    assertEquals("dn " + name, answer, interp.needName().toString());
    interp = new Interpreter(new StringReader(program));
    assertEquals("dd " + name, answer, interp.needNeed().toString());
  }

  // --- Block tests ---

  public void testBlockSingle() {
    allCheck("blockSingle", "42", "{42}");
  }

  public void testBlockMultiple() {
    allCheck("blockMultiple", "3", "{1; 2; 3}");
  }

  public void testBlockNested() {
    allCheck("blockNested", "5", "{{3; 5}}");
  }

  public void testEmptyBlockError() {
    try {
      new Interpreter(new StringReader("{}")).valueValue();
      fail("Empty block should throw ParseException");
    } catch (ParseException e) {
      // expected
    }
  }

  // --- Ref cell tests ---

  public void testRefCreate() {
    allCheck("refCreate", "(ref 5)", "ref 5");
  }

  public void testRefDeref() {
    allCheck("refDeref", "5", "!ref 5");
  }

  public void testRefQuestion() {
    allCheck("refQuestion", "true", "ref?(ref 10)");
  }

  public void testRefQuestionFalse() {
    allCheck("refQuestionFalse", "false", "ref?(10)");
  }

  public void testRefQuestionOnFun() {
    allCheck("refQuestionOnFun", "false", "ref?(map x to x)");
  }

  // --- Assignment tests ---

  public void testAssignReturnsUnit() {
    valueValueCheck("assignUnit", "unit", "let x := ref 1; in x <- 2");
  }

  public void testAssignAndRead() {
    String prog = "let x := ref 10; in {x <- 20; !x}";
    noNameCheck("assignAndRead", "20", prog);
  }

  public void testRefEquality() {
    // Two refs with the same value are NOT equal (reference equality)
    String prog = "let x := ref 10; y := ref 10; in x = y";
    allCheck("refEquality", "false", prog);
  }

  public void testRefSameEquality() {
    // A ref compared with itself IS equal
    String prog = "let x := ref 10; in x = x";
    allCheck("refSameEquality", "true", prog);
  }

  public void testRefToString() {
    String prog = "let x := ref 10; in x";
    allCheck("refToString", "(ref 10)", prog);
  }

  public void testNestedRef() {
    String prog = "let x := ref ref 5; in x";
    allCheck("nestedRef", "(ref (ref 5))", prog);
  }

  public void testRefInstructions() {
    // From the instructions: let x := ref 10; in {x <- ref 17; x}
    String prog = "let x := ref 10; in {x <- ref 17; x}";
    noNameCheck("refInstructions", "(ref (ref 17))", prog);
    // In call-by-name, x is re-evaluated, so it returns the original ref 10
    nameNameCheck("refInstructionsName", "(ref 10)", prog);
  }

  // --- Error tests ---

  public void testBangOnNonRef() {
    try {
      new Interpreter(new StringReader("!5")).valueValue();
      fail("! on non-ref should throw EvalException");
    } catch (EvalException e) {
      // expected
    }
  }

  public void testGetsOnNonRef() {
    try {
      new Interpreter(new StringReader("let x := 5; in x <- 10")).valueValue();
      fail("<- on non-ref should throw EvalException");
    } catch (EvalException e) {
      // expected
    }
  }

  // --- Mutation with closures ---

  public void testCounter() {
    String prog =
      "let c := ref 0; " +
      "    inc := map to {c <- !c + 1; !c}; " +
      "in {inc(); inc(); inc()}";
    valueValueCheck("counter", "3", prog);
  }

  public void testBlockInLet() {
    String prog = "let x := ref 0; in {x <- 1; x <- !x + 1; !x}";
    valueValueCheck("blockInLet", "2", prog);
  }

  // --- Block as expression in parens ---

  public void testBlockInParens() {
    valueValueCheck("blockInParens", "15", "({1; 5}) * 3");
  }
}

